import * as React from 'react';
import { navMenuDefaults } from '../../constants';
import { RcMenuContext } from '../context/MenuContext';

export default function useDirectionStyle(level: number): React.CSSProperties {
  const { mode, rtl, inlineIndent } = React.useContext(RcMenuContext)!;

  if (mode !== 'inline') {
    return {};
  }

  const len = level;
  const paddingInlineStart = navMenuDefaults.itemPaddingX + (len - 1) * inlineIndent;
  return rtl ? { paddingRight: paddingInlineStart } : { paddingLeft: paddingInlineStart };
}
